/// <summary>
/// Visible the new button 
/// <summary>
/// Extension class for the SalesTable form data source.
/// Controls the visibility of the "CreateLinkNew" button based on the sales status.
/// The button is visible only if the sales order has been invoiced.
/// </summary>
[ExtensionOf(formDataSourceStr(SalesTable, SalesTable))]
final class ETGSalestableformDataSourceStr_Extension
{
}

Method.Source:
public int active()
{               
    int ret = next active();
    if(ETGACFParameters::find().EnableUATSmallPoints)
    {
        SalesTable salesTable = this.cursor();
        FormRun    formRun    = this.formRun();
        if (formRun && salesTable)
        {                       
            FormButtonControl createlinkInvoice = this.formRun().design().controlName(formControlStr(SalesTable, CreateLinkNew)) as FormButtonControl;
            if (salesTable.SalesStatus == SalesStatus::Invoiced)
            {
                createlinkInvoice.visible(true);
            }
            else
            {
                createlinkInvoice.visible(false);
            }
        }
    }
    return ret;
}
